  "excerpt": "Meta description 120-155 chars con keyword",
  "content": "<p>Hook...</p><h2>Sección</h2><p>Desarrollo...</p><h3>Sub</h3><p>...</p><p>Cierre...</p>",
  "keywords": ["kw1", "kw2", "kw3", "kw4", "kw5"],
  "reading_time": 4,
  "image_prompt": "English description for AI cover image, modern editorial style"
}';

const userPrompt = d.source === 'telegram'
  ? 'Desarrollá un artículo profundo basado en esta idea: ' + d.topic
  : 'Escribí un artículo sobre: ' + d.topic + '. Keyword SEO: ' + d.keyword + '. Vertical: ' + d.vertical;

return [{
  json: {
    ...d,
    openai_body: {
      model: 'gpt-4o',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.8,
      max_tokens: 4000,
      response_format: { type: 'json_object' }
